/**
 * Generates `public/firebase-messaging-sw.js` with the Firebase config
 * matching the active environment. Runs before `ng build` and `ng serve`
 * via the prestart/prebuild npm hooks.
 *
 * Why a generated file: the SW runs in a context with no access to
 * Angular bundles, environment.ts, or process.env. Build-time codegen
 * keeps a single source of truth (the env files) and avoids drift
 * between the Angular app and the SW.
 *
 * Flag --prod selects environment.prod.ts; otherwise uses environment.ts.
 */

const fs = require('fs');
const path = require('path');

const isProd = process.argv.includes('--prod');
const envFileName = isProd ? 'environment.prod.ts' : 'environment.ts';
const envPath = path.join(__dirname, '..', 'src', 'environments', envFileName);

if (!fs.existsSync(envPath)) {
  console.error(`[generate-firebase-sw] Cannot find ${envPath}`);
  process.exit(1);
}

const envSource = fs.readFileSync(envPath, 'utf8');

const firebaseBlockMatch = envSource.match(/firebase:\s*\{([\s\S]+?)}/);
if (!firebaseBlockMatch) {
  console.error('[generate-firebase-sw] No "firebase: {...}" block found in env file');
  process.exit(1);
}

const block = firebaseBlockMatch[1];

const extract = (key) => {
  const re = new RegExp(`${key}:\\s*['"]([^'"]+)['"]`);
  const m = block.match(re);
  return m ? m[1] : '';
};

const config = {
  apiKey: extract('apiKey'),
  authDomain: extract('authDomain'),
  projectId: extract('projectId'),
  storageBucket: extract('storageBucket'),
  messagingSenderId: extract('messagingSenderId'),
  appId: extract('appId'),
};

if (!config.projectId || !config.messagingSenderId) {
  console.error(
    '[generate-firebase-sw] projectId and messagingSenderId are mandatory but missing from env'
  );
  process.exit(1);
}

const swVersion = new Date().toISOString();

const swContent = `/**
 * AUTO-GENERATED by frontend/scripts/generate-firebase-sw.js
 * Do NOT edit by hand. To change config, edit environment.ts and rebuild.
 *
 * This Service Worker handles Firebase Cloud Messaging in the background:
 *  - Receives pushes when the app is closed or the tab is in background.
 *  - Displays the OS-native notification using the payload's
 *    \`notification\` field. The Firebase SDK handles this automatically.
 *  - On notification click, focuses an open tab or opens a new one,
 *    navigating to \`data.url\`.
 *
 * Coexistence note: this SW lives in the /firebase-cloud-messaging-push-scope
 * scope (auto-registered by the Firebase SDK), distinct from /sw.js (the
 * PWA installability SW at scope /). They do not interfere.
 *
 * Generated for project: ${config.projectId}
 * Build stamp: ${swVersion}
 */

const SW_VERSION = '${swVersion}';

importScripts('https://www.gstatic.com/firebasejs/10.13.2/firebase-app-compat.js');
importScripts('https://www.gstatic.com/firebasejs/10.13.2/firebase-messaging-compat.js');

firebase.initializeApp(${JSON.stringify(config, null, 2)});

const messaging = firebase.messaging();

// Activate immediately on install / take control without reload.
self.addEventListener('install', () => {
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil(self.clients.claim());
});

/**
 * Background message handler.
 *
 * When the payload includes a \`notification\` field, the Firebase SDK
 * shows the OS notification automatically — we do NOT need to call
 * showNotification() here. Defining onBackgroundMessage explicitly is
 * required by the SDK to keep the channel alive.
 *
 * In addition to the native toast, we broadcast the data payload to every
 * open client (tab / PWA window) so any component currently mounted can
 * react to the event — e.g. the admin order-detail screen refreshing
 * automatically when a new comment arrives.
 */
messaging.onBackgroundMessage(async (payload) => {
  try {
    const allClients = await self.clients.matchAll({
      type: 'window',
      includeUncontrolled: true,
    });
    for (const client of allClients) {
      client.postMessage({
        type: 'fcm-push',
        payload: payload.data || {},
      });
    }
  } catch (err) {
    // Broadcasting is best-effort — the OS toast still appears.
    console.warn('[firebase-messaging-sw] broadcast failed:', err);
  }
});

/**
 * Notification click — same UX as /sw.js: focus an existing tab if any,
 * else open a new one. Target URL travels in payload.data.url.
 *
 * Duplicated from /sw.js by design: both SWs share the same UX so that
 * whichever shows the notification handles the click consistently.
 */
self.addEventListener('notificationclick', (event) => {
  event.notification.close();

  const fcmData = event.notification.data || {};
  const dataPayload =
    (fcmData.FCM_MSG && fcmData.FCM_MSG.data) || fcmData;
  const targetUrl = dataPayload.url || '/';

  event.waitUntil((async () => {
    const allClients = await self.clients.matchAll({
      type: 'window',
      includeUncontrolled: true,
    });

    for (const client of allClients) {
      if ('focus' in client) {
        await client.focus();
        // Always notify the focused client so it can refresh its data
        // even when the URL it already shows matches \`targetUrl\` (Angular
        // Router does not re-instantiate the component on same-URL navs).
        try {
          client.postMessage({
            type: 'fcm-notification-click',
            payload: dataPayload,
          });
        } catch {
          /* postMessage failures are non-fatal */
        }
        if ('navigate' in client) {
          try {
            await client.navigate(targetUrl);
          } catch {
            // navigate() may reject across navigations the browser
            // considers cross-origin; the focused tab is enough.
          }
        }
        return;
      }
    }

    if (self.clients.openWindow) {
      await self.clients.openWindow(targetUrl);
    }
  })());
});
`;

const outputPath = path.join(__dirname, '..', 'public', 'firebase-messaging-sw.js');
fs.writeFileSync(outputPath, swContent, 'utf8');

console.log(`[generate-firebase-sw] Generated ${outputPath}`);
console.log(`[generate-firebase-sw] Project: ${config.projectId} (${isProd ? 'prod' : 'dev'})`);
